// Flutter imports:
import 'package:flutter/foundation.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/ball.dart';
import 'package:baseball_detector_flutter/data/models/dto/player/handedness.dart';
import 'package:baseball_detector_flutter/data/models/player.dart';
import 'package:baseball_detector_flutter/views/pages/home/hooks/use_ai_coach_count.dart';

/// AI コーチレポート生成前のバリデーション結果
enum AICoachValidator {
  ok,
  notEnoughPitchingData,
  missingPitchTypes,
  missingPlayerInfo,
  usageLimitReached,
}

/// AI コーチレポート生成前のバリデーションロジック
AICoachValidator Function({
  required List<Ball> pitchingBalls,
  required Player? player,
}) useAICoachValidation() {
  final usage = useAICoachCount();

  return ({required Player? player, required List<Ball> pitchingBalls}) =>
      validateAICoachInput(
        player: player,
        pitchingBalls: pitchingBalls,
        currentUsage: usage.currentUsage,
        maxUsage: usage.maxUsage,
      );
}

@visibleForTesting
AICoachValidator validateAICoachInput({
  required Player? player,
  required List<Ball> pitchingBalls,
  required int? currentUsage,
  required int? maxUsage,
}) {
  final hasEnoughPitchingData = pitchingBalls.length >= 10;
  final hasAllPitchTypes = hasEnoughPitchingData &&
      !pitchingBalls.any(
        (ball) => ball.pitchType == null || ball.pitchType?.pitchType == 'none',
      );

  // 投球データ 10 個以上存在するか
  if (!hasEnoughPitchingData) {
    return AICoachValidator.notEnoughPitchingData;
  }

  // すべてに球種タグがついているか
  if (!hasAllPitchTypes) {
    return AICoachValidator.missingPitchTypes;
  }

  // 投球利き腕と誕生日が設定されているか
  final pitchingHand = player?.pitchingHand ?? Handedness.none;
  final hasBirthday = player?.birthday != null;

  if (pitchingHand == Handedness.none || !hasBirthday) {
    return AICoachValidator.missingPlayerInfo;
  }

  // AI コーチの利用回数上限に達していないか
  if (maxUsage != null && currentUsage != null && currentUsage >= maxUsage) {
    return AICoachValidator.usageLimitReached;
  }

  return AICoachValidator.ok;
}

