              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider
                .overrideWith(() => FakeTeamListController(result: Right([]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.unavailable);
    });

    testWidgets(
        'should return available when plan has remaining balls and item provides additional balls',
        (tester) async {
      const item = Item(
        ballUsage: 5,
        ballAvailableCount: 20,
        aiCoachUsage: 0,
