          plan: testPlan,
        ),
      );
      expect(team.aiCoachUsageStatus, AICoachUsageStatus.ok);
    });

    test('ok: 使用量が 0', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 0,
          plan: testPlan,
        ),
      );
      expect(team.aiCoachUsageStatus, AICoachUsageStatus.ok);
    });
  });

  group('canAnalyzeBall', () {
    final testPlan = createPlan();

    test('true: プランが有効で使用量も問題ない場合', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentUsage: 10,
          plan: testPlan,
        ),
      );
      expect(team.canAnalyzeBall, isTrue);
    });

    test('false: プランが期限切れの場合', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          startDate: now().subtract(const Duration(days: 100)),
          endDate: now().subtract(const Duration(days: 1)),
          currentUsage: 10,
          plan: testPlan,
        ),
      );
      expect(team.canAnalyzeBall, isFalse);
    });

    test('false: 使用量が上限に達している場合', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentUsage: 100,
          plan: testPlan,
        ),
      );
      expect(team.canAnalyzeBall, isFalse);
    });

    test('true: 期限が近づいているが使用量に問題ない場合', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          endDate: now().add(const Duration(days: 15)),
          currentUsage: 10,
          plan: testPlan,
        ),
      );
      expect(team.canAnalyzeBall, isTrue);
    });

    test('true: 使用量が接近しているがプランは有効な場合', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentUsage: 90,
          plan: testPlan,
        ),
      );
      expect(team.canAnalyzeBall, isTrue);
    });
  });

  group('canUseAiCoach', () {
    final testPlan = createPlan();

    test('true: プランが有効で使用量も問題ない場合', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 10,
          plan: testPlan,
        ),
      );
      expect(team.canUseAiCoach, isTrue);
    });

    test('false: プランが期限切れの場合', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          startDate: now().subtract(const Duration(days: 100)),
          endDate: now().subtract(const Duration(days: 1)),
          currentAiCoachUsage: 10,
          plan: testPlan,
        ),
      );
      expect(team.canUseAiCoach, isFalse);
    });

    test('false: 使用量が上限に達している場合', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 50,
          plan: testPlan,
        ),
      );
      expect(team.canUseAiCoach, isFalse);
    });

    test('true: 期限が近づいているが使用量に問題ない場合', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          endDate: now().add(const Duration(days: 15)),
          currentAiCoachUsage: 10,
          plan: testPlan,
        ),
      );
      expect(team.canUseAiCoach, isTrue);
    });

    test('true: 使用量が接近しているがプランは有効な場合', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 45,
          plan: testPlan,
        ),
      );
      expect(team.canUseAiCoach, isTrue);
    });
  });

  group('ballUsage and maxBalls with Item', () {
    final testPlan = createPlan();

    test('ballUsage: Plan のみの場合は currentUsage を返す', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentUsage: 50,
          plan: testPlan,
        ),
      );
      expect(team.ballUsage, 50);
    });

    test('ballUsage: Item のみの場合は item.ballUsage を返す', () {
      const item = Item(
        ballUsage: 20,
        ballAvailableCount: 50,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = createTeam(item: item);
      expect(team.ballUsage, 20);
    });

    test('ballUsage: Plan と Item 両方がある場合は合算する', () {
      const item = Item(
        ballUsage: 20,
        ballAvailableCount: 50,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentUsage: 30,
          plan: testPlan,
        ),
        item: item,
      );
      expect(team.ballUsage, 50); // 30 + 20
    });

    test('maxBalls: Plan のみの場合は plan.maxBalls を返す', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentUsage: 10,
          plan: testPlan,
        ),
      );
      expect(team.maxBalls, 100);
    });

    test('maxBalls: Item のみの場合は item.ballAvailableCount を返す', () {
      const item = Item(
        ballUsage: 5,
        ballAvailableCount: 30,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = createTeam(item: item);
      expect(team.maxBalls, 30);
    });

    test('maxBalls: Plan と Item 両方がある場合は合算する', () {
      const item = Item(
        ballUsage: 5,
        ballAvailableCount: 30,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentUsage: 10,
          plan: testPlan,
        ),
        item: item,
      );
      expect(team.maxBalls, 130); // 100 + 30
    });
  });

  group('aiCoachUsage and maxAICoachCount with Item', () {
    final testPlan = createPlan();

    test('aiCoachUsage: Plan のみの場合は currentAiCoachUsage を返す', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 10,
          plan: testPlan,
        ),
      );
      expect(team.aiCoachUsage, 10);
    });

    test('aiCoachUsage: Item のみの場合は item.aiCoachUsage を返す', () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 5,
        aiCoachAvailableCount: 20,
      );
      final team = createTeam(item: item);
      expect(team.aiCoachUsage, 5);
    });

    test('aiCoachUsage: Plan と Item 両方がある場合は合算する', () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 5,
        aiCoachAvailableCount: 20,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 15,
          plan: testPlan,
        ),
        item: item,
      );
      expect(team.aiCoachUsage, 20); // 15 + 5
    });

    test('maxAICoachCount: Plan のみの場合は plan.maxAiCoachs を返す', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 10,
          plan: testPlan,
        ),
      );
      expect(team.maxAICoachCount, 50);
    });

    test('maxAICoachCount: Item のみの場合は item.aiCoachAvailableCount を返す',
        () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 5,
        aiCoachAvailableCount: 20,
      );
      final team = createTeam(item: item);
      expect(team.maxAICoachCount, 20);
    });

    test('maxAICoachCount: Plan と Item 両方がある場合は合算する', () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 5,
        aiCoachAvailableCount: 20,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 10,
          plan: testPlan,
        ),
        item: item,
      );
      expect(team.maxAICoachCount, 70); // 50 + 20
    });
  });

  group('BallAnalysisUsageStatus with Item', () {
    final testPlan = createPlan();

    test('limitReached: Plan + Item の合算使用量が上限に達している場合', () {
      const item = Item(
        ballUsage: 20,
        ballAvailableCount: 30,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentUsage: 110, // 110 + 20 = 130 >= 130 (100 + 30)
          plan: testPlan,
        ),
        item: item,
      );
      expect(
          team.ballAnalysisUsageStatus, BallAnalysisUsageStatus.limitReached);
    });

    test('limitApproaching: Plan + Item の合算使用量が上限の 90% 以上の場合', () {
      const item = Item(
        ballUsage: 20,
        ballAvailableCount: 30,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentUsage: 97, // 97 + 20 = 117 >= 117 (90% of 130)
          plan: testPlan,
        ),
        item: item,
      );
      expect(team.ballAnalysisUsageStatus,
          BallAnalysisUsageStatus.limitApproaching);
    });

    test('ok: Plan + Item の合算使用量が上限の 90% 未満の場合', () {
      const item = Item(
        ballUsage: 10,
        ballAvailableCount: 30,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentUsage: 50, // 50 + 10 = 60 < 117 (90% of 130)
          plan: testPlan,
        ),
        item: item,
      );
      expect(team.ballAnalysisUsageStatus, BallAnalysisUsageStatus.ok);
    });
  });

  group('AICoachUsageStatus with Item', () {
    final testPlan = createPlan();

    test('limitReached: Plan + Item の合算使用量が上限に達している場合', () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 20,
        aiCoachAvailableCount: 30,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 60, // 60 + 20 = 80 >= 80 (50 + 30)
          plan: testPlan,
        ),
        item: item,
      );
      expect(team.aiCoachUsageStatus, AICoachUsageStatus.limitReached);
    });

    test('limitApproaching: Plan + Item の合算使用量が上限の 90% 以上の場合', () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 10,
        aiCoachAvailableCount: 30,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 62, // 62 + 10 = 72 >= 72 (90% of 80)
          plan: testPlan,
        ),
        item: item,
      );
      expect(team.aiCoachUsageStatus, AICoachUsageStatus.limitApproaching);
    });

    test('ok: Plan + Item の合算使用量が上限の 90% 未満の場合', () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 10,
        aiCoachAvailableCount: 30,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 30, // 30 + 10 = 40 < 72 (90% of 80)
          plan: testPlan,
        ),
        item: item,
      );
      expect(team.aiCoachUsageStatus, AICoachUsageStatus.ok);
    });
  });

  group('canAnalyzeBall with Item', () {
    final testPlan = createPlan();

    test('false: Plan の上限に達しているが Item に残量がある場合', () {
      const item = Item(
        ballUsage: 5,
        ballAvailableCount: 20,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentUsage: 100, // plan limit reached
          plan: testPlan,
        ),
        item: item,
      );
      // ballUsage = 100 + 5 = 105, maxBalls = 100 + 20 = 120
      // 105 < 120 なので本来は true だが、ballAnalysisUsageStatus が limitReached になる
      expect(team.canAnalyzeBall, isFalse);
    });

    test('true: Plan と Item の合算使用量が合算上限未満の場合', () {
      const item = Item(
        ballUsage: 5,
        ballAvailableCount: 20,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentUsage: 50,
          plan: testPlan,
        ),
        item: item,
      );
      // ballUsage = 50 + 5 = 55, maxBalls = 100 + 20 = 120
      // 55 < 120 なので true
      expect(team.canAnalyzeBall, isTrue);
    });
  });

  group('canUseAiCoach with Item', () {
    final testPlan = createPlan();

    test('false: Plan の上限に達しているが Item に残量がある場合', () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 5,
        aiCoachAvailableCount: 20,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 50, // plan limit reached
          plan: testPlan,
        ),
        item: item,
      );
      // aiCoachUsage = 50 + 5 = 55, maxAICoachCount = 50 + 20 = 70
      // 55 < 70 なので本来は true だが、aiCoachUsageStatus が limitReached になる
      expect(team.canUseAiCoach, isFalse);
    });

    test('true: Plan と Item の合算使用量が合算上限未満の場合', () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 5,
        aiCoachAvailableCount: 20,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 20,
          plan: testPlan,
        ),
        item: item,
      );
      // aiCoachUsage = 20 + 5 = 25, maxAICoachCount = 50 + 20 = 70
      // 25 < 70 なので true
      expect(team.canUseAiCoach, isTrue);
    });
  });
}

