    test('false: Plan の上限に達しているが Item に残量がある場合', () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 5,
        aiCoachAvailableCount: 20,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 50, // plan limit reached
          plan: testPlan,
        ),
        item: item,
      );
      // aiCoachUsage = 50 + 5 = 55, maxAICoachCount = 50 + 20 = 70
      // 55 < 70 なので本来は true だが、aiCoachUsageStatus が limitReached になる
      expect(team.canUseAiCoach, isFalse);
    });

    test('true: Plan と Item の合算使用量が合算上限未満の場合', () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 5,
        aiCoachAvailableCount: 20,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 20,
          plan: testPlan,
        ),
        item: item,
      );
      // aiCoachUsage = 20 + 5 = 25, maxAICoachCount = 50 + 20 = 70
      // 25 < 70 なので true
      expect(team.canUseAiCoach, isTrue);
    });
  });
}

