        ballUsage: 10,
        ballAvailableCount: 30,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentUsage: 50, // 50 + 10 = 60 < 117 (90% of 130)
          plan: testPlan,
        ),
        item: item,
      );
      expect(team.ballAnalysisUsageStatus, BallAnalysisUsageStatus.ok);
    });
  });

  group('AICoachUsageStatus with Item', () {
    final testPlan = createPlan();

    test('limitReached: Plan + Item の合算使用量が上限に達している場合', () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 20,
        aiCoachAvailableCount: 30,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 60, // 60 + 20 = 80 >= 80 (50 + 30)
          plan: testPlan,
        ),
        item: item,
      );
      expect(team.aiCoachUsageStatus, AICoachUsageStatus.limitReached);
    });

    test('limitApproaching: Plan + Item の合算使用量が上限の 90% 以上の場合', () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 10,
        aiCoachAvailableCount: 30,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 62, // 62 + 10 = 72 >= 72 (90% of 80)
          plan: testPlan,
        ),
        item: item,
      );
      expect(team.aiCoachUsageStatus, AICoachUsageStatus.limitApproaching);
    });

    test('ok: Plan + Item の合算使用量が上限の 90% 未満の場合', () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 10,
        aiCoachAvailableCount: 30,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 30, // 30 + 10 = 40 < 72 (90% of 80)
          plan: testPlan,
        ),
        item: item,
      );
      expect(team.aiCoachUsageStatus, AICoachUsageStatus.ok);
    });
  });

  group('canAnalyzeBall with Item', () {
    final testPlan = createPlan();

    test('false: Plan の上限に達しているが Item に残量がある場合', () {
      const item = Item(
        ballUsage: 5,
        ballAvailableCount: 20,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentUsage: 100, // plan limit reached
          plan: testPlan,
        ),
        item: item,
      );
      // ballUsage = 100 + 5 = 105, maxBalls = 100 + 20 = 120
      // 105 < 120 なので本来は true だが、ballAnalysisUsageStatus が limitReached になる
      expect(team.canAnalyzeBall, isFalse);
    });

    test('true: Plan と Item の合算使用量が合算上限未満の場合', () {
      const item = Item(
        ballUsage: 5,
        ballAvailableCount: 20,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentUsage: 50,
          plan: testPlan,
        ),
        item: item,
      );
      // ballUsage = 50 + 5 = 55, maxBalls = 100 + 20 = 120
      // 55 < 120 なので true
      expect(team.canAnalyzeBall, isTrue);
    });
  });

  group('canUseAiCoach with Item', () {
    final testPlan = createPlan();

    test('false: Plan の上限に達しているが Item に残量がある場合', () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 5,
        aiCoachAvailableCount: 20,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 50, // plan limit reached
          plan: testPlan,
        ),
        item: item,
      );
      // aiCoachUsage = 50 + 5 = 55, maxAICoachCount = 50 + 20 = 70
      // 55 < 70 なので本来は true だが、aiCoachUsageStatus が limitReached になる
      expect(team.canUseAiCoach, isFalse);
    });

    test('true: Plan と Item の合算使用量が合算上限未満の場合', () {
      const item = Item(
        ballUsage: 0,
        ballAvailableCount: 0,
        aiCoachUsage: 5,
        aiCoachAvailableCount: 20,
      );
      final team = createTeam(
        teamPlan: createTeamPlan(
          currentAiCoachUsage: 20,
          plan: testPlan,
        ),
        item: item,
      );
      // aiCoachUsage = 20 + 5 = 25, maxAICoachCount = 50 + 20 = 70
      // 25 < 70 なので true
      expect(team.canUseAiCoach, isTrue);
    });
  });
}

